// PixiJS v8 可接收预建 canvas；先挂画布可避免异步 init 前容器为空
const el = document.getElementById('pixi'); el.style.height = `${spec.height ?? 400}px`;
const canvas = document.createElement('canvas'); canvas.style.cssText = `display:block;width:100%;height:100%;background:${data.background ?? '#0b1020'}`; el.appendChild(canvas);
const { Application, Graphics } = await import('https://cdn.jsdelivr.net/npm/pixi.js@8/+esm');
const app = new Application(); await app.init({ canvas, resizeTo: el, background: data.background ?? '#0b1020', antialias: data.antialias ?? true });
for (const s of data.shapes) { const g = new Graphics(); if (s.type === 'circle') g.circle(s.x, s.y, s.radius ?? 40); else g.rect(s.x, s.y, s.width ?? 80, s.height ?? 80); g.fill({ color: s.fill, alpha: s.alpha ?? 1 }); app.stage.addChild(g); }

